package com.baize.flux.connectors.jdbc;
import com.baize.flux.api.configuration.*; import com.baize.flux.api.factory.SinkFactory; import com.baize.flux.api.sink.SinkWriter; import com.baize.flux.api.table.FluxRow;
public final class JdbcSinkFactory implements SinkFactory { public String factoryIdentifier(){return "jdbc";} public OptionRule optionRule(){return JdbcOptions.sinkRule();} public SinkWriter<FluxRow> createSink(ReadonlyConfig c){return new JdbcSinkWriter(c.get(JdbcOptions.URL),c.get(JdbcOptions.USERNAME),c.get(JdbcOptions.PASSWORD),c.get(JdbcOptions.TABLE),c.get(JdbcOptions.BATCH_SIZE));} }
